const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;

const isWooOrder = !!(body.id && body.billing && body.line_items);

// WooCommerce webhook source map
// Add more businesses here as you onboard them:
// 'https://clientstore.com/' => 'their-business-id'
const WOO_SOURCE_MAP = {
  'https://www.sknatural.com/': 'ea7bc145-de5f-4c42-9a79-d95853a1dc73',
  'https://sknatural.com/':     'ea7bc145-de5f-4c42-9a79-d95853a1dc73'
};

let lead = {};

if (isWooOrder) {
  // Identify business from WooCommerce webhook source header
  const wcSource = headers['x-wc-webhook-source'] || '';
  const business_id_override = WOO_SOURCE_MAP[wcSource] || null;

  lead = {
    source:               'woocommerce_order',
    wc_order_id:          body.id,
    name:                 ((body.billing.first_name || '') + ' ' + (body.billing.last_name || '')).trim() || 'Unknown',
    email:                body.billing.email || null,
    phone:                body.billing.phone || null,
    city:                 body.billing.city || null,
    country:              body.billing.country || null,
    order_total:          parseFloat(body.total) || 0,
    currency:             body.currency || 'PKR',
    products:             (body.line_items || []).map(i => i.name).join(', '),
    webhook_secret:       body.webhook_secret || null,
    business_id_override: business_id_override,
    raw_payload:          body
  };
} else {
  lead = {
    source:               body.source || 'manual',
    wc_order_id:          null,
    name:                 body.name || body.full_name || 'Unknown',
    email:                body.email || null,
    phone:                body.phone || null,
    city:                 body.city || null,
    country:              body.country || 'PK',
    order_total:          parseFloat(body.order_total || body.budget || 0),
    currency:             body.currency || 'PKR',
    products:             body.products || body.interested_in || null,
    webhook_secret:       $input.first().json.headers?.['x-wc-webhook-secret'] || body.webhook_secret || null,
    business_id_override: null,
    raw_payload:          body
  };
}

if (!lead.email && !lead.phone) {
  throw new Error('Lead must have email or phone');
}

return [{ json: { ...lead, receivedAt: new Date().toISOString() } }];

const lead = $('Parse Lead Data').first().json;
const raw  = $input.first().json;

let business_id = null;

// Priority 1: direct override from WooCommerce source map
if (lead.business_id_override) {
  business_id = lead.business_id_override;
}
// Priority 2: Supabase lookup result (direct object)
else if (raw.business_id && raw.is_active) {
  business_id = raw.business_id;
}
// Priority 3: Supabase lookup result (array)
else if (Array.isArray(raw) && raw[0]?.business_id) {
  business_id = raw[0].business_id;
}
// Priority 4: nested body array
else if (Array.isArray(raw.body) && raw.body[0]?.business_id) {
  business_id = raw.body[0].business_id;
}

if (!business_id) {
  throw new Error('Business not found. Check webhook_secret or WOO_SOURCE_MAP.');
}

return [{ json: { ...lead, business_id } }];

const d = $input.first().json;

let score = 50;
const reasons = [];

if (d.email)  { score += 10; reasons.push('Has email'); }
if (d.phone)  { score += 10; reasons.push('Has phone'); }

if (d.order_total >= 5000)      { score += 20; reasons.push('High order value'); }
else if (d.order_total >= 1000) { score += 10; reasons.push('Medium order value'); }
else if (d.order_total > 0)     { score += 5;  reasons.push('Has order value'); }

if (d.source === 'woocommerce_order') { score += 15; reasons.push('WooCommerce order'); }

score = Math.min(score, 100);

let grade, priority;
if (score >= 80)      { grade = 'A'; priority = 'high'; }
else if (score >= 60) { grade = 'B'; priority = 'medium'; }
else                  { grade = 'C'; priority = 'low'; }

return [{
  json: {
    ...d,
    lead_score:    score,
    lead_grade:    grade,
    lead_priority: priority,
    score_reasons: reasons
  }
}];

const scored  = $('Score Lead').first().json;
const raw     = $input.first().json;
const records = Array.isArray(raw) ? raw : (Array.isArray(raw.body) ? raw.body : []);

const isExistingCustomer = records.length > 0;

return [{ json: { ...scored, isExistingCustomer } }];

const d = $('Check If Customer').first().json;

const priority = d.lead_priority;
const score    = d.lead_score;
const emoji    = priority === 'high' ? '🔴' : (priority === 'medium' ? '🟡' : '🟢');

let msg = `${emoji} *New Lead Captured!*\n\n`;
msg += `👤 *Name:* ${d.name}\n`;
if (d.email)         msg += `📧 *Email:* ${d.email}\n`;
if (d.phone)         msg += `📞 *Phone:* ${d.phone}\n`;
if (d.city)          msg += `📍 *City:* ${d.city}\n`;
if (d.products)      msg += `🛍️ *Interested in:* ${d.products}\n`;
if (d.order_total > 0) msg += `💰 *Order Value:* ${d.currency} ${d.order_total.toLocaleString()}\n`;
msg += `\n`;
msg += `📊 *Score:* ${score}/100 (Grade ${d.lead_grade})\n`;
msg += `⚡ *Priority:* ${priority.toUpperCase()}\n`;
msg += `📥 *Source:* ${d.source}\n`;
msg += `\n_BizFlow CRM_`;

return [{ json: { ...d, notificationMsg: msg, isNew: true } }];

const notif = $('Build Notification').first().json;
const raw   = $input.first().json;
const biz   = Array.isArray(raw) ? raw[0] : (Array.isArray(raw.body) ? raw.body[0] : raw);

const chatId = biz?.telegram_chat_id
  || notif?.telegram_chat_id
  || notif?.raw_payload?.telegram_chat_id
  || null;

return [{ json: { ...notif, telegram_chat_id: chatId ? String(chatId) : null } }];

const d = $('Check If Customer').first().json;
const raw = $input.first().json;
const saved = Array.isArray(raw) ? raw[0] : (Array.isArray(raw.body) ? raw.body[0] : raw);

const lead_id = saved?.id || saved?.lead_id || null;

return [{
  json: {
    ...d,
    lead_id,
    activity: {
      business_id:   d.business_id,
      lead_id:       lead_id,
      action:        'created',
      lead_score:    d.lead_score,
      lead_grade:    d.lead_grade,
      lead_priority: d.lead_priority,
      source:        d.source,
      order_total:   d.order_total,
      note:          `Lead created via ${d.source}. Score: ${d.lead_score}/100 (${d.lead_grade})`,
      created_at:    new Date().toISOString()
    }
  }
}];
